python3 -c "
import sys

baseline = {}
opt = {}

with open('size-baseline') as f:
    for line in f:
        parts = line.split()
        if len(parts) == 2 and parts[0] not in ('TOTAL', '--------------------'):
            baseline[parts[0]] = int(parts[1])

with open('size-opt7') as f:
    for line in f:
        parts = line.split()
        if len(parts) == 2 and parts[0] not in ('TOTAL', '--------------------'):
            opt[parts[0]] = int(parts[1])

changed = []
for k in baseline:
    if k in opt and baseline[k] != opt[k]:
        d = baseline[k] - opt[k]
        pct = d/baseline[k]*100
        changed.append((k, baseline[k], opt[k], d, pct))

changed.sort(key=lambda x: -x[3])
print(f'{'Function':<25} {'Before':>8} {'After':>8} {'Delta':>8} {'%':>7}')
print('-'*58)
for k,b,o,d,p in changed:
    print(f'{k:<25} {b:>8} {o:>8} {-d:>+8} {-p:>+7.1f}%')
"
